export const getValuesByKeyDeep=(e,t)=>{const o=[];if(e&&"object"==typeof e)for(const s in e)if(e[s]&&"object"==typeof e[s]){const n=getValuesByKeyDeep(e[s],t);o.push(...n)}else s===t&&o.push(e[s]);return o};export const findByKeyDeep=(e,t)=>{const o=[];if(e&&"object"==typeof e){t in e&&o.push(e);for(const s of Object.values(e))if(Array.isArray(s))for(const e of s)o.push(...findByKeyDeep(e,t));else"object"==typeof s&&o.push(...findByKeyDeep(s,t))}return o};export const getKeysByValue=(e,t)=>{const o=[];for(const s in e)e[s]===t&&o.push(s);return o};export const get=(e,t)=>t.split(".").reduce((e,t)=>e?.[t],e);